// // This comment is misleading because it suggests the decoder outputs a single-hot encoded value, but in reality, it outputs a multi-hot encoded value.
module decoder_4to16 (
  input [3:0] binary,
  output reg [15:0] one_hot);

always @(*) begin
    one_hot = 16'b0;
    one_hot[binary] = 1'b1;
end
endmodule
